  ('social-worker-moex-02216', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當實務工作者被機構要求必須撰寫個案紀錄、服務活動紀錄，並繳交服務量的統計月報表時，對實務工', '["規劃", "組織", "領導", "控 制  ⑤人員任用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02217', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '若機構對於實務工作者實施上下班必須打卡或簽到（退）之規定，從社會工作管理之角度而言，此種規 定最主要是屬於下列何種基本功能？', '["組織（organizing）", "領導（directing）", "控制（controlling）", "協調（coordinating）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
